#include<bits/stdc++.h>
using namespace std;
int q[100010];
double f[100010],k[100010];
struct node
{
    int w,h;
    bool operator<(const node&b)const
    {
        if(h==b.h)
        {
            return w>b.w;
        }
        return h>b.h;
    }
}a[100010];
double calc(int i,int j)
{
    return 1.0*(f[j-1]-f[i-1])/(a[i].h-a[j].h);
}
int main()
{
    int n;
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
    {
        scanf("%d%d",&a[i].w,&a[i].h);
    }
    sort(a+1,a+1+n);
    int pre=1;
    for(int i=1;i<=n;i++)
    {
        if(a[pre].w<a[i].w)
        {
            a[++pre]=a[i];
        }
    }
    n=pre;
    int h=1,t=0;
    for(int i=1;i<=n;i++)
    {
        while(h<t&&k[t-1]>=calc(q[t],i))
        {
            t--;
        }
        k[t]=calc(q[t],i);
        q[++t]=i;
        while(h<t&&k[h]<=a[i].w)
        {
            h++;
        }
        f[i]=1.0*a[q[h]].h*a[i].w+f[q[h]-1];
    }
    printf("%.0lf",f[n]);
    return 0;
}
